const raw = $input.first().json.body.transcricao;

const limpo = raw
  .replace(/^\d+$/gm, '')
  .replace(/\d{2}:\d{2}:\d{2},\d{3} --> \d{2}:\d{2}:\d{2},\d{3}/g, '')
  .replace(/\n{2,}/g, '\n')
  .split('\n')
  .map(l => l.trim())
  .filter(l => l.length > 3)
  .join(' ');

const transcricaoLimitada = limpo.length > 6000 ? limpo.slice(0, 6000) + '...' : limpo;

return [{
  json: {
    turma:       $input.first().json.body.turma,
    linkLoom:    $input.first().json.body.linkLoom,
    linkSlides:  $input.first().json.body.linkSlides,
    transcricao: transcricaoLimitada,
    data:        new Date().toLocaleDateString('pt-BR')
  }
}];

const textoJson = $input.first().json.text ?? '';

let dados;
try {
  const limpo = textoJson.replace(/```json/gi, '').replace(/```/g, '').trim();
  dados = JSON.parse(limpo);
} catch (e) {
  dados = {
    tema: 'Aula de tecnologia',
    conceitos: ['conceito principal'],
    ferramentas: ['ferramenta principal'],
    atividade_aula: 'Atividade prática realizada em aula',
    ferramenta_principal: 'ferramenta'
  };
}

const anterior = $('Limpa SRT').first().json;

return [{
  json: {
    turma:                anterior.turma,
    data:                 anterior.data,
    linkLoom:             anterior.linkLoom,
    linkSlides:           anterior.linkSlides,
    tema:                 dados.tema,
    conceitos:            (dados.conceitos ?? []).join(', '),
    ferramentas:          (dados.ferramentas ?? []).join(', '),
    atividade_aula:       dados.atividade_aula,
    ferramenta_principal: dados.ferramenta_principal,
    query1:               `${dados.tema} tutorial português`,
    query2:               `${dados.ferramenta_principal} documentação oficial`
  }
}];

// Após o Merge, temos 2 items: index 0 = Busca 1, index 1 = Busca 2
const items = $input.all();

const extrairLinks = (item) => {
  const resultados = item?.json?.organic_results ?? [];
  return resultados.slice(0, 2).map(r => `- [${r.title}](${r.link})`).join('\n');
};

const links1 = items[0] ? extrairLinks(items[0]) : '';
const links2 = items[1] ? extrairLinks(items[1]) : '';

const linksFormatados = [links1, links2].filter(l => l.length > 0).join('\n');

// Recupera os dados do contexto salvo antes das buscas
const base = $('Parse JSON e monta queries').first().json;

return [{
  json: {
    ...base,
    linksSerp: linksFormatados || '- Nenhum link encontrado na busca'
  }
}];

